
class ObjectMetricSource {final CrossVersionObjectReference describedObject; final MetricIdentifier metric; final MetricTarget target; ObjectMetricSource({required this.describedObject, required this.metric, required this.target}); factory ObjectMetricSource.fromJson(Map<String, dynamic> json) {return ObjectMetricSource(describedObject: CrossVersionObjectReference.fromJson(json['describedObject']), metric: MetricIdentifier.fromJson(json['metric']), target: MetricTarget.fromJson(json['target']));} Map<String, dynamic> toJson() {return {'describedObject' : describedObject.toJson(), 'metric' : metric.toJson(), 'target' : target.toJson()};}}
